// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper: Get priority badge color
function getPriorityVariant(priority?: string) {
  switch (priority) {
    case 'high': return 'error';
    case 'medium': return 'warning';
    case 'low': return 'success';
    default: return 'default';
  }
}

// Helper: Extract initials from assignee
function getInitials(assignee?: string) {
  if (!assignee) return '?';
  return assignee.split(' ').map((w) => w[0]).join('').toUpperCase().slice(0, 2);
}

// Task card component
function TaskCard({
  task,
  onEdit,
  onMove,
}: {
  task: Props['tasks'][0];
  onEdit: (task: Props['tasks'][0]) => void;
  onMove: (taskId: string, targetColumn: string) => void;
}) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');

  const handleSave = () => {
    onEdit({ ...task, title: editTitle });
    setIsEditing(false);
  };

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md" border>
      <Stack gap="var(--ggui-spacing-2)" align="stretch">
        {isEditing ? (
          <Input
            label="Task title"
            value={editTitle}
            onChange={setEditTitle}
            size="sm"
          />
        ) : (
          <Text
            variant="body"
            weight="medium"
            as={Clickable}
            onClick={() => setIsEditing(true)}
            aria-label="Double-click to edit task title"
            style={{ cursor: 'pointer', padding: 'var(--ggui-spacing-1)' }}
          >
            {task.title || 'Untitled'}
          </Text>
        )}

        <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
          {task.priority && (
            <Badge variant={getPriorityVariant(task.priority)} size="sm">
              {task.priority}
            </Badge>
          )}
          {task.assignee && (
            <Avatar name={task.assignee} size={24} shape="circle" />
          )}
        </Row>

        {task.dueDate && (
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Due: {new Date(task.dueDate).toLocaleDateString()}
          </Text>
        )}

        {isEditing ? (
          <Row gap="var(--ggui-spacing-1)" justify="end">
            <Button
              variant="ghost"
              size="xs"
              onClick={() => setIsEditing(false)}
            >
              Cancel
            </Button>
            <Button
              variant="primary"
              size="xs"
              onClick={handleSave}
            >
              Save
            </Button>
          </Row>
        ) : (
          <Row gap="var(--ggui-spacing-1)" justify="end">
            <Button
              variant="ghost"
              size="xs"
              aria-label={`Edit task: ${task.title}`}
              leftIcon={<Icon name="edit" size={14} />}
              onClick={() => setIsEditing(true)}
            >
              Edit
            </Button>
            <Dropdown
              trigger={<Button variant="ghost" size="xs"><Icon name="move" size={14} /></Button>}
              options={[
                { value: 'move-to-todo', label: 'To Do', disabled: task.column === 'todo' },
                { value: 'move-to-progress', label: 'In Progress', disabled: task.column === 'in-progress' },
                { value: 'move-to-done', label: 'Done', disabled: task.column === 'done' },
              ]}
              value=""
              onChange={(value) => {
                const targetColumn = value.replace('move-to-', '');
                onMove(task.id || '', targetColumn);
              }}
              placement="bottom-end"
            />
          </Row>
        )}
      </Stack>
    </Card>
  );
}

// Column component
function KanbanColumn({
  column,
  tasks,
  onEditTask,
  onMoveTask,
  onAddTask,
}: {
  column: Props['columns'][0];
  tasks: Props['tasks'];
  onEditTask: (task: Props['tasks'][0]) => void;
  onMoveTask: (taskId: string, targetColumn: string) => void;
  onAddTask: (title: string, columnId: string, priority: 'low' | 'medium' | 'high') => void;
}) {
  const [showForm, setShowForm] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const handleAddTask = () => {
    if (newTitle.trim()) {
      onAddTask(newTitle, column.id || '', newPriority);
      setNewTitle('');
      setNewPriority('medium');
      setShowForm(false);
    }
  };

  return (
    <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg" border>
      <Stack gap="var(--ggui-spacing-4)" align="stretch">
        <Row align="center" justify="between">
          <Heading level={4}>{column.name}</Heading>
          <Badge variant="secondary" size="sm">{tasks.length}</Badge>
        </Row>

        <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

        <Stack gap="var(--ggui-spacing-3)" align="stretch">
          {tasks.map((task) => (
            <TaskCard
              key={task.id}
              task={task}
              onEdit={onEditTask}
              onMove={onMoveTask}
            />
          ))}
        </Stack>

        {showForm ? (
          <Stack gap="var(--ggui-spacing-2)" align="stretch">
            <Input
              label="Task title"
              placeholder="Enter task title..."
              value={newTitle}
              onChange={setNewTitle}
              size="sm"
            />
            <Select
              label="Priority"
              value={newPriority}
              onChange={(v) => setNewPriority(v as 'low' | 'medium' | 'high')}
              options={[
                { value: 'low', label: 'Low' },
                { value: 'medium', label: 'Medium' },
                { value: 'high', label: 'High' },
              ]}
              size="sm"
            />
            <Row gap="var(--ggui-spacing-2)" justify="end">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => {
                  setShowForm(false);
                  setNewTitle('');
                  setNewPriority('medium');
                }}
              >
                Cancel
              </Button>
              <Button
                variant="primary"
                size="sm"
                onClick={handleAddTask}
              >
                Add Task
              </Button>
            </Row>
          </Stack>
        ) : (
          <Button
            variant="outline"
            size="sm"
            fullWidth
            onClick={() => setShowForm(true)}
          >
            + Add Task
          </Button>
        )}
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State
  const [tasks, setTasks] = useState<Props['tasks']>(props.tasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);

  // Sync stream updates
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (!task) return;

      setTasks((prev) => {
        if (action === 'create') {
          return [...prev, task];
        } else if (action === 'move' || action === 'edit') {
          return prev.map((t) => (t.id === task.id ? task : t));
        } else if (action === 'delete') {
          return prev.filter((t) => t.id !== task.id);
        }
        return prev;
      });
    }
  }, [taskChanged.latest]);

  // Compute totals
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  // Handlers
  const handleEditTask = (updatedTask: Props['tasks'][0]) => {
    setTasks((prev) => prev.map((t) => (t.id === updatedTask.id ? updatedTask : t)));
    if (updatedTask.id) {
      taskUpdate({
        action: 'edit',
        taskId: updatedTask.id,
        data: { column: updatedTask.column || 'todo', title: updatedTask.title },
      });
    }
  };

  const handleMoveTask = (taskId: string, targetColumn: string) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t))
    );
    taskUpdate({
      action: 'move',
      taskId,
      data: { column: targetColumn },
    });
  };

  const handleAddTask = (title: string, columnId: string, priority: 'low' | 'medium' | 'high' = 'medium') => {
    const newTask: Props['tasks'][0] = {
      id: `task-${Date.now()}`,
      title,
      column: columnId === 'todo' ? 'todo' : 'todo',
      priority,
    };
    setTasks((prev) => [...prev, newTask]);
    taskUpdate({
      action: 'create',
      taskId: newTask.id || '',
      data: { column: 'todo', title },
    });
  };

  // Group tasks by column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Props['tasks']> = {};
    props.columns.forEach((col) => {
      grouped[col.id || ''] = tasks.filter((t) => t.column === col.id);
    });
    return grouped;
  }, [tasks, props.columns]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)" align="stretch">
          <Heading level={1}>Kanban Board</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Manage your tasks across columns
          </Text>
        </Stack>

        {/* Summary bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg" border background="var(--ggui-color-surfaceVariant)">
          <Row gap="var(--ggui-spacing-6)" align="center" justify="start">
            <Stack gap="var(--ggui-spacing-1)" align="start">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Total Tasks
              </Text>
              <Heading level={3} color="var(--ggui-color-onSurface)">{totalTasks}</Heading>
            </Stack>
            <Divider orientation="vertical" margin="0" />
            <Stack gap="var(--ggui-spacing-1)" align="start">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Completed
              </Text>
              <Heading level={3} color="var(--ggui-color-success-600)">{completedTasks}</Heading>
            </Stack>
            <Spacer size="flex" />
            <Progress value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0} variant="success" showLabel />
          </Row>
        </Card>

        {/* Kanban columns */}
        <Row gap="var(--ggui-spacing-4)" align="start" justify="start" wrap>
          {props.columns.map((column) => (
            <Box
              key={column.id}
              style={{
                flex: '0 1 calc(33.333% - var(--ggui-spacing-3))',
                minWidth: '280px',
              }}
            >
              <KanbanColumn
                column={column}
                tasks={tasksByColumn[column.id || '']}
                onEditTask={handleEditTask}
                onMoveTask={handleMoveTask}
                onAddTask={handleAddTask}
              />
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}
